 676	/* Decrement VAR_NAME by one.  This includes the special variables
 677	   ibase, obase, and scale. */
 678	
 679	void
 680	decr_var (var_name)
 681	     int var_name;
 682	{
 683	  bc_var *var_ptr;
 684	
 685	  switch (var_name)
 686	    {
 687	
 688	    case 0: /* ibase */
 689	      if (i_base > 2)
 690		i_base--;
 691	      else
 692		rt_warn ("ibase too small in --");
 693	      break;
 694	      
 695	    case 1: /* obase */
 696	      if (o_base > 2)
 697		o_base--;
 698	      else
 699		rt_warn ("obase too small in --");
 700	      break;
 701	
 702	    case 2: /* scale */
 703	      if (scale > 0)
 704		scale--;
 705	      else
 706		rt_warn ("scale can not be negative in -- ");
 707	      break;
 708	
 709	#if defined(READLINE) || defined(LIBEDIT)
 710	    case 3: /* history */
 711	      n_history--;
 712	      if (n_history >= 0)
 713		HISTORY_SIZE(n_history);
 714	      else
 715		{
 716		  n_history = -1;
 717		  rt_warn ("history is negative, set to unlimited");
 718		  UNLIMIT_HISTORY;
 719		}
 720	#endif
 721	
