 744	     (index == 0 && !bc_is_zero (ex_stack->s_num))) 
 745	    rt_error ("Array %s subscript out of bounds.", a_names[var_name]);
 746	  else
 747	    {
 748	      num_ptr = get_array_num (var_name, index);
 749	      if (num_ptr != NULL)
 750		{
 751		  pop ();
 752		  bc_sub (*num_ptr, _one_, num_ptr, 0);
 753		}
 754	    }
