 931			{
 932			  free_a_tree (a_temp->a_value->a_tree,
 933				       a_temp->a_value->a_depth);
 934			  free (a_temp->a_value);
 935			}
 936		      free (a_temp);
 937		    }
 938		} 
 939	      list = list->next;
 940	    }
