107	  /* Add the current number to the end of the string. */
108	  if (args->arg_is_var)
109	    if (len != 1) 
110	      sprintf (sval, "*%d,", args->av_name);
111	    else
112	      sprintf (sval, "*%d", args->av_name);
113	  else
114	    if (len != 1) 
